import crypto from 'node:crypto';

import bcrypt from 'bcrypt';
import { Secret, TOTP } from 'otpauth';
import QRCode from 'qrcode';

import { AuditEventType, logAuditEvent } from '../../utils/auditLogger';
import { getErrorMessage } from '../../utils/errorHandler';
import { logger } from '../../utils/logger';
import { cache } from '../../utils/redis';
import { UserService } from '../user/UserService';

export interface TwoFactorSetup {
  secret: string;
  qrCodeUrl: string;
  backupCodes: string[];
}

export interface LockoutStatus {
  isLocked: boolean;
  lockedUntil?: Date;
  remainingAttempts: number;
  attemptCount: number;
}

export class TwoFactorService {
  private readonly userService: UserService;
  private readonly bcryptCost: number;
  private static readonly usedTotpTokens = new Map<string, number>();
  private static readonly tokenReuseCleanupTimer = setInterval(() => {
    const now = Date.now();
    for (const [key, expiresAt] of TwoFactorService.usedTotpTokens.entries()) {
      if (expiresAt <= now) {
        TwoFactorService.usedTotpTokens.delete(key);
      }
    }
  }, 60 * 1000).unref();
  private static readonly tokenValidityWindow = 1;

  constructor() {
    this.userService = new UserService();
    this.bcryptCost = this.getBcryptCost();
  }

  /**
   * Amendment 2: Get bcrypt cost factor with validation & fallback
   * Range: 10-14 (higher = more secure but slower)
   * Default: 12 (OWASP-recommended balance)
   */
  private getBcryptCost(): number {
    const envCost = process.env.BACKUP_CODE_BCRYPT_COST;

    // Default: 12 (industry standard)
    if (!envCost) {
      logger.debug('BACKUP_CODE_BCRYPT_COST not set, using default 12');
      return 12;
    }

    // Validate: Must be 10-14
    const cost = Number.parseInt(envCost, 10);
    if (Number.isNaN(cost) || cost < 10 || cost > 14) {
      logger.warn('Invalid BACKUP_CODE_BCRYPT_COST, using default 12', {
        value: envCost,
        parsed: cost,
      });
      return 12;
    }

    logger.debug('Using BACKUP_CODE_BCRYPT_COST', { cost });
    return cost;
  }

  /**
   * Amendment 4: Detect if hash is bcrypt format
   * bcrypt format: Starts with "$2b$", length >= 58
   */
  private isBcryptHash(hash: string): boolean {
    return hash.startsWith('$2b$') && hash.length >= 58;
  }

  private getReplayTtlSeconds(): number {
    const periodSeconds = 30;
    return periodSeconds * (TwoFactorService.tokenValidityWindow * 2 + 1);
  }

  private getTokenReplayKey(userId: string, token: string): string {
    const tokenHash = crypto.createHash('sha256').update(token.trim().toUpperCase()).digest('hex');
    return `2fa:totp:used:${userId}:${tokenHash}`;
  }

  private async isTokenReplayed(key: string): Promise<boolean> {
    try {
      const seenInSharedCache = await cache.exists(key);
      if (seenInSharedCache) {
        return true;
      }
    } catch (error: unknown) {
      logger.debug('2FA replay cache exists check failed; using local fallback', {
        key,
        error: getErrorMessage(error),
      });
    }

    const localExpiry = TwoFactorService.usedTotpTokens.get(key);
    return typeof localExpiry === 'number' && localExpiry > Date.now();
  }

  private async markTokenAsUsed(key: string): Promise<void> {
    const ttlSeconds = this.getReplayTtlSeconds();

    try {
      const stored = await cache.set(key, { usedAt: Date.now() }, ttlSeconds);
      if (stored) {
        return;
      }
    } catch (error: unknown) {
      logger.debug('2FA replay cache set failed; using local fallback', {
        key,
        error: getErrorMessage(error),
      });
    }

    TwoFactorService.usedTotpTokens.set(key, Date.now() + ttlSeconds * 1000);
  }
  /**
   * Generate a new TOTP secret and QR code for authenticator apps
   */
  public async generateSecret(
    username: string,
    issuer: string = process.env.TOTP_ISSUER || 'Fringe Core'
  ): Promise<TwoFactorSetup> {
    // Generate secret
    const secretBytes = new Secret({ size: 32 });

    // Create TOTP instance for QR code generation
    const totp = new TOTP({
      issuer,
      label: username,
      algorithm: 'SHA1',
      digits: 6,
      period: 30,
      secret: secretBytes,
    });

    const qrCodeUrl = await QRCode.toDataURL(totp.toString());

    // Generate backup codes
    const backupCodes = this.generateBackupCodes(10);

    return {
      secret: secretBytes.base32,
      qrCodeUrl,
      backupCodes,
    };
  }

  /**
   * Verify a TOTP token
   */
  public async verifyToken(secret: string, token: string, userId?: string): Promise<boolean> {
    const totp = new TOTP({
      algorithm: 'SHA1',
      digits: 6,
      period: 30,
      secret: Secret.fromBase32(secret),
    });

    // validate returns the token delta or null if invalid
    // window: 1 allows 1 time step before and after current time
    const normalizedToken = token.trim().toUpperCase();
    const delta = totp.validate({
      token: normalizedToken,
      window: TwoFactorService.tokenValidityWindow,
    });
    if (delta === null) {
      return false;
    }

    if (!userId) {
      return true;
    }

    const replayKey = this.getTokenReplayKey(userId, normalizedToken);
    const replayed = await this.isTokenReplayed(replayKey);
    if (replayed) {
      logger.warn('Rejected replayed 2FA token', { userId });
      return false;
    }

    await this.markTokenAsUsed(replayKey);
    return true;
  }

  /**
   * Generate backup codes
   */
  public generateBackupCodes(count: number = 10): string[] {
    const codes: string[] = [];
    for (let i = 0; i < count; i++) {
      // Generate 8-character alphanumeric code
      const code = crypto.randomBytes(4).toString('hex').toUpperCase();
      codes.push(code);
    }
    return codes;
  }

  /**
   * Amendment 1: Hash backup codes for secure storage (NOW ASYNC with parallelization)
   * Replaces unsalted SHA256 with bcrypt (salted, slow hash)
   *
   * Amendment 5: Performance timing reference
   * - Cost 10: ~20ms per hash
   * - Cost 12: ~50ms per hash (default, OWASP-recommended)
   * - Cost 14: ~200ms per hash
   *
   * Sequential (old): 10 * 50ms = ~500ms
   * Parallel (new):   ~50ms (all 10 in Promise.all)
   */
  public async hashBackupCodes(codes: string[]): Promise<string[]> {
    try {
      // Parallel bcrypt hashing (Amendment 1)
      return await Promise.all(codes.map(code => bcrypt.hash(code.toUpperCase(), this.bcryptCost)));
    } catch (error: unknown) {
      logger.error('Failed to hash backup codes', {
        error: getErrorMessage(error),
        codeCount: codes.length,
      });
      throw new Error('Failed to hash backup codes');
    }
  }

  /**
   * Amendment 4: Verify a backup code against hashed codes (NOW ASYNC with format detection)
   * Handles both bcrypt (new) and SHA256 (old) hashes for backward compatibility
   *
   * Format detection:
   * - bcrypt: Starts with "$2b$", length >= 58
   * - SHA256: 64 hex characters (old format, for backward compatibility)
   */
  public async verifyBackupCode(code: string, hashedCodes: string[]): Promise<boolean> {
    try {
      // Normalize input
      const normalizedCode = code.toUpperCase().trim();

      // Try each hash (check bcrypt first, then SHA256 for backward compat)
      for (const hashedCode of hashedCodes) {
        // Amendment 4: Format detection
        if (this.isBcryptHash(hashedCode)) {
          // New format: Use bcrypt comparison
          const matches = await bcrypt.compare(normalizedCode, hashedCode);
          if (matches) {
            return true; // Matched bcrypt hash
          }
        } else {
          // Old format: SHA256 string comparison (backward compatibility)
          const hashedInput = crypto.createHash('sha256').update(normalizedCode).digest('hex');
          if (hashedInput === hashedCode) {
            return true; // Matched SHA256 hash
          }
        }
      }

      // No match found
      return false;
    } catch (error: unknown) {
      logger.error('Failed to verify backup code', {
        error: getErrorMessage(error),
        hashCount: hashedCodes.length,
      });
      return false; // Fail safely on error
    }
  }

  /**
   * Remove a used backup code from the list
   * Handles both bcrypt and SHA256 formats (Amendment 4)
   */
  public async removeBackupCode(code: string, hashedCodes: string[]): Promise<string[]> {
    try {
      const normalizedCode = code.toUpperCase().trim();
      const result: string[] = [];

      for (const hashedCode of hashedCodes) {
        let shouldRemove = false;

        // Amendment 4: Format detection
        if (this.isBcryptHash(hashedCode)) {
          // Bcrypt format: Compare
          shouldRemove = await bcrypt.compare(normalizedCode, hashedCode);
        } else {
          // SHA256 format: String equality
          const hashedInput = crypto.createHash('sha256').update(normalizedCode).digest('hex');
          shouldRemove = hashedInput === hashedCode;
        }

        if (!shouldRemove) {
          result.push(hashedCode); // Keep hash that didn't match
        }
        // else: Skip this hash (it's the one to remove)
      }

      return result;
    } catch (error: unknown) {
      logger.error('Failed to remove backup code', {
        error: getErrorMessage(error),
        hashCount: hashedCodes.length,
      });
      return hashedCodes; // Return unchanged if error
    }
  }

  /**
   * Track failed 2FA attempt
   * Implements progressive lockout strategy
   */
  public async trackFailedAttempt(userId: string): Promise<void> {
    try {
      const user = await this.userService.getUserById(userId);
      if (!user) {
        throw new Error('User not found');
      }
      const attempts = (user.failedTwoFactorAttempts || 0) + 1;

      // Progressive lockout strategy
      // 5 attempts = 15 minutes
      // 10 attempts = 1 hour
      // 15+ attempts = 24 hours
      let lockoutUntil: Date | undefined;

      if (attempts >= 15) {
        lockoutUntil = new Date(Date.now() + 24 * 60 * 60 * 1000); // 24 hours
        logger.warn('User locked out for 24 hours', { userId, attempts });
      } else if (attempts >= 10) {
        lockoutUntil = new Date(Date.now() + 60 * 60 * 1000); // 1 hour
        logger.warn('User locked out for 1 hour', { userId, attempts });
      } else if (attempts >= 5) {
        lockoutUntil = new Date(Date.now() + 15 * 60 * 1000); // 15 minutes
        logger.warn('User locked out for 15 minutes', { userId, attempts });
      }

      await this.userService.updateUser(userId, {
        failedTwoFactorAttempts: attempts,
        twoFactorLockedUntil: lockoutUntil,
      });

      logger.info('Failed 2FA attempt tracked', {
        userId,
        attemptCount: attempts,
        lockedUntil: lockoutUntil,
      });

      const lockoutMessageSuffix = lockoutUntil
        ? ` - locked until ${lockoutUntil.toISOString()}`
        : '';

      logAuditEvent({
        eventType: AuditEventType.AUTH_FAILURE,
        userId,
        resource: 'auth.totp',
        action: 'verify_failed',
        message: `Failed 2FA attempt for user ${userId}: attempt ${attempts}${lockoutMessageSuffix}`,
        metadata: { attemptCount: attempts, lockedUntil: lockoutUntil?.toISOString() },
      });
    } catch (error: unknown) {
      logger.error('Failed to track 2FA attempt', {
        userId,
        error: getErrorMessage(error),
      });
      throw error;
    }
  }

  /**
   * Check if user is locked out from 2FA verification
   */
  public async checkLockout(userId: string): Promise<LockoutStatus> {
    try {
      const user = await this.userService.getUserById(userId);
      if (!user) {
        throw new Error('User not found');
      }
      const now = new Date();

      // Check if currently locked
      if (user.twoFactorLockedUntil && user.twoFactorLockedUntil > now) {
        return {
          isLocked: true,
          lockedUntil: user.twoFactorLockedUntil,
          remainingAttempts: 0,
          attemptCount: user.failedTwoFactorAttempts || 0,
        };
      }

      // If lockout expired, clear it
      if (user.twoFactorLockedUntil && user.twoFactorLockedUntil <= now) {
        await this.userService.updateUser(userId, {
          failedTwoFactorAttempts: 0,
          twoFactorLockedUntil: undefined,
        });

        return {
          isLocked: false,
          remainingAttempts: 15,
          attemptCount: 0,
        };
      }

      // Not locked, calculate remaining attempts
      const maxAttempts = 15;
      const attempts = user.failedTwoFactorAttempts || 0;
      const remaining = Math.max(0, maxAttempts - attempts);

      return {
        isLocked: false,
        remainingAttempts: remaining,
        attemptCount: attempts,
      };
    } catch (error: unknown) {
      logger.error('Failed to check lockout status', {
        userId,
        error: getErrorMessage(error),
      });
      // Fail secure - assume locked on error
      return {
        isLocked: true,
        remainingAttempts: 0,
        attemptCount: 0,
      };
    }
  }

  /**
   * Reset failed attempts (called on successful verification)
   */
  public async resetFailedAttempts(userId: string): Promise<void> {
    try {
      await this.userService.updateUser(userId, {
        failedTwoFactorAttempts: 0,
        twoFactorLockedUntil: undefined,
      });

      logger.info('Failed 2FA attempts reset', { userId });
    } catch (error: unknown) {
      logger.error('Failed to reset 2FA attempts', {
        userId,
        error: getErrorMessage(error),
      });
      throw error;
    }
  }

  /**
   * Calculate lockout duration based on attempt count
   */
  public calculateLockoutDuration(attempts: number): number {
    if (attempts >= 15) {
      return 24 * 60 * 60 * 1000; // 24 hours
    } else if (attempts >= 10) {
      return 60 * 60 * 1000; // 1 hour
    } else if (attempts >= 5) {
      return 15 * 60 * 1000; // 15 minutes
    }
    return 0; // No lockout
  }
}
